# Geometry module with shapes and utilities

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

class Shape:
    label: str

    def __init__(self, label: str):
        self.label = label

    def area(self) -> float:
        return 0.0

class Circle(Shape):
    center: Point
    radius: float

    def __init__(self, label: str, center: Point, radius: float):
        super().__init__(label)
        self.center = center
        self.radius = radius

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, label: str, width: float, height: float):
        super().__init__(label)
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

