# Calculator module that operates on shapes from geometry module
from geometry import Shape, Circle, Rectangle, Point

class ShapeCalculator:
    total_area: float

    def __init__(self):
        self.total_area = 0.0

    def add_shape(self, shape: Shape) -> None:
        self.total_area += shape.area()

    def get_total(self) -> float:
        return self.total_area

def compare_shapes(s1: Shape, s2: Shape) -> str:
    area1: float = s1.area()
    area2: float = s2.area()

    if area1 > area2:
        return s1.label
    elif area2 > area1:
        return s2.label
    else:
        return "equal"
